mapper.select:
SELECT * FROM ( SELECT id, 'join' AS type, family_id, applicant_user_id, applicant_name, relation_desc, NULL AS member_id, NULL AS member_name, NULL AS changes_json, NULL AS reject_reason, NULL AS reviewer_id, status, create_time, NULL AS reviewed_at FROM join_request WHERE family_id = #{familyId}
AND 1=1
AND status = #{status}
UNION ALL
SELECT id, 'edit' AS type, family_id, applicant_user_id, NULL AS applicant_name, NULL AS relation_desc, member_id, member_name, changes_json, reject_reason, reviewer_id, status, create_time, reviewed_at FROM edit_request WHERE family_id = #{familyId}
AND 1=1
AND status = #{status}
) AS approvals
type = #{type}
ORDER BY create_time DESC

SELECT * FROM ( SELECT id, 'join' AS type, family_id, applicant_user_id, applicant_name, relation_desc, NULL AS member_id, NULL AS member_name, NULL AS changes_json, NULL AS reject_reason, NULL AS reviewer_id, status, create_time, NULL AS reviewed_at FROM join_request
AND 1=1
AND status = #{status}
UNION ALL
SELECT e.id, 'edit' AS type, e.family_id, e.applicant_user_id, u.name AS applicant_name, NULL AS relation_desc, e.member_id, e.member_name, e.changes_json, e.reject_reason, e.reviewer_id, e.status, e.create_time, e.reviewed_at FROM edit_request e LEFT JOIN user u ON e.applicant_user_id = u.id
AND 1=1
AND e.status = #{status}
) AS approvals
type = #{type}
ORDER BY create_time DESC
